    def initialize_board(self):
        colors = [Fore.BLACK + 'X', Fore.RED + 'O']
        for row in range(8):
            color_index = row % 2
            for col in range(4 if row < 3 else 5, 4 + (3 - row % 2), 2):
                self.board[row][col] = Piece(colors[color_index], col, row)
                color_index = 1 - color_index

    def print_board(self):
        print("   " + " ".join([chr(i) for i in range(97, 105)]))
        for row in range(8):
            print(str(row + 1) + " |" + "|".join(piece.symbol if piece else ' ' for piece in self.board[row]) + "|")
            print("  " + "--" * 8)

    def move_piece(self, start_pos, end_pos):
        col_start, row_start = ord(start_pos[0]) - 97, int(start_pos[1]) - 1
        col_end, row_end = ord(end_pos[0]) - 97, int(end_pos[1]) - 1

        if self.board[row_start][col_start] and (row_end - row_start) % 2 == 0:
            piece = self.board[row_start][col_start]
            capture = self.capture_piece(col_start, col_end, row_start, row_end)
            if capture:
                self.board[capture[0]][capture[1]] = None
            piece.move(row_end, col_end)
            self.board[row_end][col_end] = piece

