# game.py

from board import Board
from player import Player

class Game:
    def __init__(self):
        self.board = Board()
        self.player1 = Player(Fore.BLACK + 'X')
        self.player2 = Player(Fore.RED + 'O')
        self.current_player = self.player1

    def start_game(self):
        while True:
            self.board.print_board()
            if self.current_player == self.player1:
                start_pos, end_pos = input("Player 1 (Black) move: ").split('-')
                self.current_player.make_move(self.board)
            else:
                start_pos, end_pos = input("Player 2 (Red) move: ").split('-')
                self.current_player.make_move(self.board)

if __name__ == "__main__":
    game = Game()
